module top_module(
   clk,
   reset,
   count_out
);input            clk;
    input            reset;
    output  [3:0]    count_out;

    reg  [3:0]        invalid_count;

    always @(posedge clk or negedge reset) begin
        if (~reset) begin
            invalid_count <= 4'b0000;
        end
        else begin
            invalid_count <= invalid_count + 1;
        end
    end

    assign count_out = invalid_count;

endmodule
